import{_ as e,o as a,c as t,j as p,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"割腕者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/割腕者.md","filePath":"4.资源分区/7.物品与装备/6.套装/割腕者.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/割腕者.md"};function o(d,r,l,_,i,c){return a(),t("div",null,[...r[0]||(r[0]=[p("h1",{id:"割腕者",tabindex:"-1"},[b("割腕者 "),p("a",{class:"header-anchor",href:"#割腕者","aria-label":'Permalink to "割腕者"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),n('<h1 id="割腕者-1" tabindex="-1">割腕者 <a class="header-anchor" href="#割腕者-1" aria-label="Permalink to &quot;割腕者&quot;">​</a></h1><p>割腕者</p><p>浴缸里漂浮着许多苍白的手。那些我曾经深爱过的人的手。<br> 用于治疗身体的药物以无法想象的速度高速发展着，但用于治疗心理的药物没有</p><p>武器：C+3000<br> 武器伤害：10L<br> 武器特性：轻灵<br> 武器体积：1</p><p>沾满血迹的手上握着这把刀，刀刃似乎充盈着着流不尽的鲜血。</p><p>或许是为了减少割腕时的痛苦，刀刃被刻意打磨得锋利无比，能够轻而易举地割断血肉。</p><p>这把刀似乎也能阻止血肉的再生。</p><p>刀刃会将追求幸福的意志一并撕裂，而这将永不停止。</p><p>持有者的意志力上限减1，由这把武器施加的攻击将会附带2点不可豁免的精神束缚异常点数，但是由这些异常点数导致的毁灭性后果为厌世而不是定身。</p><p>这把武器造成精神伤害而不是穿刺伤害，</p><p>你在攻击命中时，敌人需以强韧豁免对抗你的伤害出目，若失败则进入【沉没】状态，陷入【沉没】状态的敌人在意志豁免上具有【劣化1】，持续一场景，这是一个C级别创伤来源的效果。</p><p>以一个自由动作消耗2点意志力的同时对自己造成3点不可豁免的严重伤害，这个场景中所有处于【沉没】状态的敌人，每轮结束时，其身上每具有1点精神束缚异常点数，其在意志豁免上就收到1DP的士气减值，最多以此法收到5DP减值，持续一轮。</p><p>如果你此时持有【司书作战书页】，那么你可以将这把武器一半的基础属性和全部特性加入攻击中。</p><p>护甲：C+3000</p><p>护甲防御 10/10</p><p>护甲上怪异的花纹像极了皮革切痕和斑斑血迹。</p><p>这件护甲本身蕴含着过多的悲伤与痛苦，可它也能使穿戴者抵御多数的心灵攻击。</p><p>当灰心失意，精神脆弱的员工穿上这件护甲时，它可能会给他们带来哀伤的梦，令人难以入眠。</p><p>这件护甲为你带来决心检定上的【9加骰】。</p><p>这件护甲提供了仅针对挥砍伤害的2点物理伤害吸收，以及仅面对挥砍伤害的【劣化1】。</p><p>当你被攻击时，攻击者每拥有一点精神束缚异常点数，这件护甲提供的护甲防御就获得1点附加成功，最多获得3点。</p><p>套装效果：</p><p>割腕：</p><p>当你处于理智的情绪时，用刀片割腕很不容易，你必须拥有强大的意志力才能重复许多次。只有当你把自己你的手腕当做一块肉来割时，你才有可能成功——只有当你对死亡充满了巨大的渴望时，你才有可能成功。</p><p>我后悔当她向我寻求帮助时我没有问其原因；我后悔我没有注意到她用手表遮住了她的手腕；我后悔我没有意识到当我和她说话时，她总是刻意将手腕藏了起来；我后悔我没有意识到也许从某个时刻起，我再听不到她的笑声了。</p><p>当你同时持有上述2件装备时，此时护甲提供的物理伤害吸收升级为全伤害吸收，且劣化1开始对所有攻击生效，但是如果你的决心在11以下，那么你的意志力上限减少3点，且每次长休时，恢复的意志力减少1点。</p><p>受【沉沦】状态影响的敌人，每轮结束时，其身上每具有1点精神束缚异常点数，其在意志豁免上就收到1DP的士气减值，最多以此法收到4DP减值，持续一轮，由此法获得的减值可以与武器的减值相叠加。</p><p>饰品：C+1000<br> 占据手套位</p><p>我一辈子都会后悔——我后悔当她找我借那把工业用刀时，我没能询问出她的理由；我也后悔我没有注意到她故意隐藏在手表下的手腕。</p><p>当我和她聊天时，她总是刻意将手腕裹起来。本来脸上总是挂着笑容的她，却越来越频繁地在公司里徘徊，眼神呆滞，木然无光。</p><p>这是一块染血的，缠在手腕部位的纱布，其下掩盖着深刻的伤疤和绝望，</p><p>你的所有攻击可以转变为以意志豁免来进行对抗。</p><p>当你使用割腕者武器命中敌人时，敌人需要以一个强韧豁免对抗你的伤害出目，若其失败，则其陷入【抑郁】状态，持续一场景，这是一个C级别、创伤来源的效果，</p><p>处于【抑郁】状态下的敌人，每轮结束时，其每具有1精神束缚异常点数，其在意志豁免上就具有3DP的士气减值，最多计算3点精神束缚异常点数，这个减值持续一轮，</p><p>并且如果此时其具有超过3点精神束缚异常点数并且处于【沉没】状态，那么【沉没】的【劣化1】升级为【劣化2】。</p><p>技艺：割腕<br> C+1000</p><p>仅有在兑换了其他3件资源后才能兑换，一次性获得下属所有技艺</p><p>沉没</p><p>类型：攻击技<br> 等级：C<br> 动作：标准动作<br> 射程：触及<br> 持续：1轮<br> 效果：<br> 立刻进行一次攻击，若此时你已经处于割腕状态，则在本轮中升级你造成的【沉沦】效果，处于升级后的【沉沦】状态的敌人，会使敌人在本轮中每次被击中，都会受到1点不可豁免的精神束缚异常点数。</p><p>升级状态仅持续一轮，随后处于【沉沦】状态的敌人受到其正常状态下的影响。</p><p>抑郁</p><p>类型：攻击技<br> 等级：C<br> 动作：标准动作<br> 射程：触及<br> 持续：一轮<br> 条件：上一轮使用了【沉没】<br> 效果：<br> 立刻进行一次攻击，若敌人此时已处于【抑郁】状态，则升级敌人身上的【抑郁】状态，升级后的【抑郁】状态，每点精神束缚异常点数还会额外使敌人的攻击检定上受到3层【麻痹】，最多计算3点精神束缚异常点数。</p><p>升级状态仅持续一轮，随后处于【抑郁】状态的敌人受到其正常状态下的影响。</p><p>【麻痹】：攻击者在攻击检定上受到1附加成功的士气减值，若其附加成功不足，则减少其3DP攻击检定。</p><p>瘆白之手</p><p>类型：攻击技<br> 等级：C<br> 动作：整轮动作<br> 射程：触及<br> 持续：一轮<br> 条件：上一轮使用了【抑郁】<br> 效果：<br> 立刻进行一次攻击，敌人需要以意志豁免对抗你的伤害出目，若抵抗失败则其在本轮中不能格挡，不能选取你为攻击目标，这是一个C级别影响心灵来源的胁迫效果。</p><p>本次攻击中，敌人每具有1点精神束缚异常点数，其在意志豁免减免你的攻击时，就收到1点附加成功上的士气减值，做多受到4点减值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',49)])])}const C=e(s,[["render",o]]);export{f as __pageData,C as default};
